LSRankManager = {}

LSRankManager.Ranks = {}

function LSRankManager:addPlayerRank(player)

    self:removeExitPlayer()
    local flag = true
    player.property.fame = FameConfig:getNameByKill(player.property.kill)
    for i, Value in pairs(self.Ranks) do
        if Value.userId == player.userId then
            Value:setName(player.name)
            if player.property.isConcealPower then
                Value:setMuscle(0)
            else
                Value:setMuscle(player.property.muscleMass)
            end
            Value:setFame(player.property.fame)
            Value:setKill(player.curKill)
            local advanced = AdvancedConfig:getAdvancedConfig(player.property.advancedLevel)
            if advanced and player.property.isConcealPower == false then
                Value:setStage(advanced.gradeId)
            else
                Value:setStage(0)
            end
            Value:setScore(player.score)
            flag = false
            break
        end
    end

    local advanced = AdvancedConfig:getAdvancedConfig(player.property.advancedLevel)
    local gradeId = 0
    if advanced and player.property.isConcealPower == false then
        gradeId = advanced.gradeId
    end
    local oneRank = LSPlayerRank.new(player.userId, player.name, player.property.muscleMass, player.property.fame, player.curKill, gradeId, player.score)
    if flag then
        table.insert(self.Ranks, oneRank)
    end

    self:sortPlayerRank()

    for _, Value in pairs(self.Ranks) do
        self:senderOnePlayerRank(Value)
    end

end

function LSRankManager:removePlayerRank(userId)
    for i, Value in pairs(self.Ranks) do
        if Value.userId == userId then
            table.remove(self.Ranks, i)
            break
        end
    end

    self:removeExitPlayer()

    self:sortPlayerRank()

    for _, Value in pairs(self.Ranks) do
        self:senderOnePlayerRank(Value)
    end

end

function LSRankManager:updatePlayerRank(player, isReal)
    local beReal = isReal or false
    player.property.fame = FameConfig:getNameByKill(player.property.kill)

    for i, Value in pairs(self.Ranks) do
        if Value.userId == player.userId then
            Value:setName(player.name)
            if player.property.isConcealPower and not beReal then
                Value:setMuscle(0)
                LogUtil.log("updatePlayerRank player.userId " .. tostring(player.userId) .. " isReal " .. tostring(isReal))
            else
                Value:setMuscle(player.property.muscleMass)
            end
            --Value:setMuscle(player.property.muscleMass)
            Value:setFame(player.property.fame)
            Value:setKill(player.curKill)
            local advanced = AdvancedConfig:getAdvancedConfig(player.property.advancedLevel)
            if advanced and (beReal or player.property.isConcealPower == false) then
                Value:setStage(advanced.gradeId)
            else
                Value:setStage(0)
            end
            Value:setScore(player.score)
            break
        end
    end
    if beReal then
        return
    end
    self:removeExitPlayer()

    self:sortPlayerRank()

    for _, Value in pairs(self.Ranks) do
        self:senderOnePlayerRank(Value)
    end

end

function LSRankManager:updateAllPlayerRealRank()
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        self:updatePlayerRank(player, true)
    end
    self:removeExitPlayer()
    self:sortPlayerRank()
end

function LSRankManager:senderOnePlayerRank(oneRank)

    local data = {
        rank = oneRank.rank,
        name = oneRank.name,
        muscle = oneRank.muscle,
        fame = oneRank.fame,
        kill = oneRank.kill,
        stage = oneRank.stage,
        score = oneRank.score
    }

    local player = PlayerManager:getPlayerByUserId(oneRank.userId)
    if player then
        GamePacketSender:SendLiftingSimulatorMeRank(player.rakssid, json.encode(data))
    end

end

function LSRankManager:senderAllRankToOnePlayer(player)
    local tempRanks = {}

    for _, Value in pairs(self.Ranks) do
        local data = {
            rank = Value.rank,
            name = Value.name,
            muscle = Value.muscle,
            fame = Value.fame,
            kill = Value.kill,
            stage = Value.stage,
            score = Value.score
        }
        table.insert(tempRanks, data)
    end

    GamePacketSender:SendLiftingSimulatorAllOtherRank(player.rakssid, json.encode(tempRanks))

end

function LSRankManager:senderAllPlayerRank()

    local tempRanks = {}

    for _, Value in pairs(self.Ranks) do
        local data = {
            rank = Value.rank,
            name = Value.name,
            muscle = Value.muscle,
            fame = Value.fame,
            kill = Value.kill,
            stage = Value.stage,
            score = Value.score
        }
        table.insert(tempRanks, data)
    end

    for _, Value in pairs(self.Ranks) do
        local player = PlayerManager:getPlayerByUserId(Value.userId)
        if player then
            GamePacketSender:SendLiftingSimulatorAllOtherRank(player.rakssid, json.encode(tempRanks))
        end
    end


end

function LSRankManager:sortPlayerRank()
    table.sort(self.Ranks, function(a, b)
        if a.score ~= b.score then
            return a.score > b.score
        end
        if a.kill ~= b.kill then
            return a.kill > b.kill
        end
        if a.stage ~= b.stage then
            return a.stage > b.stage
        end
        if a.muscle ~= b.muscle then
            return a.muscle > b.muscle
        end
        return false
    end)

    for rank, Value in pairs(self.Ranks) do
        Value:setRank(rank)
    end
end

--删除掉线玩家
function LSRankManager:removeExitPlayer()
    local i = 1
    while (i <= #self.Ranks) do
        local player = PlayerManager:getPlayerByUserId(self.Ranks[i].userId)
        if player then
            i = i + 1
        else
            table.remove(self.Ranks, i)
        end
    end
end

return LSRankManager

